import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Set;

@Slf4j
public class BasisRszVerdelerDmfa extends BasisRszVerdelerDmfappl {

    public static final int MIN_GRENS_PENSIOENSTELSEL_CODE_APK = 40;
    public static final int MAX_GRENS_PENSIOENSTELSEL_CODE_APK = 80;

    private static final List<Integer> BEZOLDINGSCODES_MET_VOLLEDIGE_VRIJSTELING = Arrays.asList(
            DmfaBezoldigingscode.VVA_AUTO.getCode(),
            DmfaBezoldigingscode.EVG_BED_VR.getCode(),
            DmfaBezoldigingscode.VV_EVG_VW.getCode());

    private static final Set<DmfaBezoldigingscode> BEZOLDIGINGS_CODES_DMFA_ZONDER_BASIS = Sets.immutableEnumSet(
            DmfaBezoldigingscode.VRIJGESTELD_OF_NVT,
            DmfaBezoldigingscode.V_VRIJ_RSZ,
            DmfaBezoldigingscode.V_SOC_MAR,
            DmfaBezoldigingscode.VOORDEEL_NIET_ONWP_SOC_MARIBEL,
            DmfaBezoldigingscode.UIT_VERG);

    private final IsPool2Ter isPool2Ter;

    private final AsbestfondsManager asbestfondsManager;

    public BasisRszVerdelerDmfa(
            @NonNull DmfapplBasisBijdrageService dmfapplBasisBijdrageService,
            @NonNull APKPrincipeService apkPrincipeService,
            RegulManager regulManager,
            @NonNull Hoedanigheid hoedanigheid,
            @NonNull Gsd typeGsd,
            CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel,
            LocalDate gegevensDatum,
            BasisRszVerdelerOptions options,
            IsPool2Ter isPool2Ter,
            AsbestfondsManager asbestfondsManager) {
        super(dmfapplBasisBijdrageService, apkPrincipeService, regulManager, null, hoedanigheid, typeGsd, categorieKengetalStatuutPensioenstelsel, gegevensDatum,
                options);
        this.isPool2Ter = isPool2Ter;
        this.asbestfondsManager = asbestfondsManager;
    }

    private static void verdeelBasisRszBijdrageEgalisatieBijdrage(DmfapplWnkengetal werknemersKengetal, LoonElement loonElement, Money bedrag) {
        if (werknemersKengetal == DmfapplWnkengetal.LOKALE_MANDATARIS_NIET_BECHERMD_DMFA || werknemersKengetal == DmfapplWnkengetal.LOKALE_MANDATARIS_BESCHERMD) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY, bedrag);
        } else {
            loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
        }
    }

    @Override
    protected void verdeelBasisRszBijdrageGsd(Money bedrag) {
        Statuut statuut = getCategorieKengetalStatuutPensioenstelsel().getStatuut();
        if (getTypeGsd() == Gsd.GSD && statuut.komtInAanmerkingGsd()) {
            getLoonElement().putProperty(RekenBasisRszKey.BASIS_GSD_KEY, bedrag);
        }
    }

    @Override
    protected void verdeelBasisRszBijdrageGsdVlaanderen(DmfapplWnkengetal werknemersKengetalBijdrage, Money bedrag) {
        Kengetal werknemersKengetal = getWerknemersKengetal(werknemersKengetalBijdrage);
        boolean isTeVerdelenGsdMin = getTypeGsd() == Gsd.V_MIN && werknemersKengetal.isGeenLokaleMandataris();
        Statuut statuut = getCategorieKengetalStatuutPensioenstelsel().getStatuut();
        boolean isGsdVlaanderen = getTypeGsd() == Gsd.V_PLUS || isTeVerdelenGsdMin;
        if (isGsdVlaanderen && statuut.komtInAanmerkingGsd()) {
            getLoonElement().putProperty(RekenBasisRszKey.BASIS_GSD_KEY, bedrag);
        }
    }

    @Override
    protected void verdeelBasisRszNaarWerknemersKengetalBijdrage(
            DmfapplWnkengetal werknemersKengetal, DmfapplWnkengetal werknemersKengetalBijdrage, DmfapplStatuutDmfappl statuutDmfappl, Money bedrag) {
        LoonElement loonElement = getLoonElement();
        switch (werknemersKengetalBijdrage) {
            case VAKREG_PRIVE:
                loonElement.putProperty(RekenBasisRszKey.BASIS_VAKREG_PRIVESECTOR_KEY, bedrag);
                break;
            case ARBEIDSONGEVALLEN:
                loonElement.putProperty(RekenBasisRszKey.BASIS_BIJZONDERE_BIJDRAGE_ARBEIDSONGEVALLEN_KEY, bedrag);
                break;
            case ASTBESTFONDS:
                if (asbestfondsManager.isAsbestfondsActief(getGegevensDatum())) {
                    loonElement.putProperty(RekenBasisRszKey.BASIS_BIJZONDERE_BIJDRAGE_ASBESTFONDS_KEY, bedrag);
                }
                break;
            case BIJZONDERE_BIJDRAGE_BUITENWETTELIJK_PENSIOEN:
            case NGNATPERS_BIJZBIJDR_BW_PENS_R_EXWN:
            case BIJZBIJDR_BW_PENS_ONDERNPLAN:
                loonElement.putProperty(RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY, bedrag);
                break;
            case EGALISATIEBIJDRAGE:
                verdeelBasisRszBijdrageEgalisatieBijdrage(werknemersKengetal, loonElement, bedrag);
                break;
            case BIJDRAGE_DUBBEL_VAKANTIEGELD:
            case NGNATPERS_BIJDR_DUBBEL_VAKG_DMFA:
                loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
                break;
            case BIJDRAGE_VERKEERSBOETE:
                loonElement.putProperty(RekenBasisRszKey.BASIS_TERUGBETALING_VERKEERSBOETES_KEY, bedrag);
                break;
            case PENSIOENBIJDRAGE_VASTBENOEMD_GEMEENSCHAPPELIJK_STELSEL:
            case PENSIOENBIJDRAGE_VASTBENOEMD_NIEUW_AANGESLOTEN:
            case PENSIOENBIJDRAGE_VASTBENOEMD_GEINTEGREERD_LOKALE_POLITIE:
            case BASISPENSBIJDR_EX_GEMEENSCH:
            case BASISPENSBIJDR_EX_NIEUW_RIJKSDIENST_HOOG_PERC:
            case BASISPENSBIJDR_LOKALE_POLITIE:
            case BASISPENSBIJDR_AANGSL_NA2011_LAAG_PERC:
            case BASISPENSBIJDR_EX_VOORZORGINST_SPECIFIEK_BIJDRVOET:
            case BASISPENSBIJDR_PARASTATALEN:
            case BASISPENSBIJDR_STATUTAIRE_WERKNEMERS:
            case BASISPENSIOENBIJDR_GEWESTELIJKE_ONTVANGERS:
                if (Eredienst.hasPensioenBijdrage(statuutDmfappl)) {
                    loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY, bedrag);
                }
                break;
            case PENS2_PROLOCUS:
                Prolocus.verdeelBasisRsz(bedrag, loonElement, getOptions());
                verdeelBasisBonusTweedePensioenPijler(bedrag, loonElement);
                break;
            case PENS2_PROVANT:
            case PENS2_ETHIAS_PENSIONFUND:
                BasisRszVerdelerOptions options = getOptions();
                if (options.isBerekenTweedePensioenPijler()) {
                    loonElement.putProperty(RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY, bedrag);
                    verdeelBasisBonusTweedePensioenPijler(bedrag, loonElement);
                }
                break;
            case BIJDRAGE_OP_TAO:
                loonElement.putProperty(RekenBasisRszKey.BASIS_TAO_KEY, bedrag);
                break;
            case VOLLEDIGE_VRIJSTELLING:
                loonElement.putProperty(RekenBasisRszKey.BASIS_NIET_ONDERWORPEN_KEY, bedrag);
                break;
            case WERKLOOSHEIDSBIJDRAGE_1_69:
            case C846:
            case TERUGBETALING_GEWONE_SOCIALEZEKERHEID_BIJDRAGE_SYNDICAAL_GED:
            case TERUGBETALING_PENSIOENBIJDRAGE_VASTBENOEMD_SYNDICAAL_GEDETAC:
            case TERUGBETALING_PENSIOENBIJDRAGE_1_69_SYNDICAAL_GEDETACHEERD:
            case CODE_843:
            case CODE_878:
            case WERKLOOSHEIDSBIJDRAGE_1_60:
            case BIJZONDERE_BIJDRAGE_SOCIALE_ZEKERHEID:
                //doe niets
                break;
            case BIJDRAGE_GSD:
                verdeelBasisRszBijdrageGsd(bedrag);
                break;
            case BIJDRAGE_GSD_VLAANDEREN:
                verdeelBasisRszBijdrageGsdVlaanderen(werknemersKengetal, bedrag);
                break;
            case BIJZONDERE_BIJDRAGE_MOBILITEITSBUDGET_3E_PIJLER:
                loonElement.putProperty(RekenBasisRszKey.BASIS_MOBILITEITSBUDGET_KEY, bedrag);
                break;

            //PRIVE
            case ECONOMISCHE_WERKLOOSHEID: // 800
                // GEEN BASIS
                break;
            case FONDS_SLUITING_ONDERNEMINGEN: // 810
                loonElement.putProperty(RekenBasisRszKey.BASIS_FONDS_SLUITING_ONDERNEMING_KEY, bedrag);
                break;
            case FSO_NIET_COMMERCIELE_WERKGEVERS: // 811
                loonElement.putProperty(RekenBasisRszKey.BASIS_FSO_NIET_COMMERCIELE_WERKGEVERS_KEY, bedrag);
                break;
            case VERBREKINGSVERGOEDINGEN_SLUITINGSFONDS: // 812
                VerbrekingsvergoedingenSluitingsfonds.setOnLoonElement(loonElement, bedrag);
                break;
            case FONDSEN_BESTAANSZEKERHEID_ARBEIDERS: //820
                loonElement.putProperty(RekenBasisRszKey.BASIS_FONDSEN_BESTAANSZEKERHEID_ARBEIDERS_KEY, bedrag);
                break;
            case SECTORAAL_PENSIOENFONDS_ARBEIDERS: // 825
                BijdrageSectoraalPensioenfondsArbeiders.setOnLoonElement(loonElement, bedrag, getOptions());
                break;
            case FONDSEN_BESTAANSZEKERHEID_BEDIENDEN: // 830
                loonElement.putProperty(RekenBasisRszKey.BASIS_FONDSEN_BESTAANSZEKERHEID_BEDIENDEN_KEY, bedrag);
                break;
            case SECTORAAL_PENSIOENFONDS_BEDIENDEN: // 835
                loonElement.putProperty(RekenBasisRszKey.BASIS_SECTORAAL_PENSIOENFONDS_BEDIENDEN_KEY, bedrag);
                break;
            case WERKGELEGENHEID_EN_VORMING: // 852
                loonElement.putProperty(RekenBasisRszKey.BASIS_WERKGELEGENHEID_EN_VORMING_KEY, bedrag);
                break;
            case TIJDELIJKE_WERKLOOSHEID: // 859
                loonElement.putProperty(RekenBasisRszKey.BASIS_TIJDELIJKE_WERKLOOSHEID_KEY, bedrag);
                break;
            case BIJDRAGE_OP_WINST_PERCENTAGE: // 861
                loonElement.putProperty(RekenBasisRszKey.BASIS_WINST_PREMIE_KEY, bedrag);
                break;
            case CORONAPREMIE_KOOPKRACHTPREMIE: //801
                loonElement.putProperty(RekenBasisRszKey.BASIS_CORONAPREMIE_KEY, bedrag);
                break;
            default:
                doRegulExceptionRszregimeNietGeprogrammeerd(werknemersKengetalBijdrage, loonElement);
                break;
        }
    }

    private void verdeelBasisBonusTweedePensioenPijler(Money bedrag, LoonElement loonElement) {
        if (getOptions().isBonusTweedePensioenPijler()) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, bedrag);
        }
    }

    private void doRegulExceptionRszregimeNietGeprogrammeerd(DmfapplWnkengetal werknemersKengetalBijdrage, LoonElement loonElement) {
        log.debug("werknemersKengetalBijdrage {}({}) niet geprogrammeerd", werknemersKengetalBijdrage.getLangeTekst(), werknemersKengetalBijdrage.getCode());
        getRegulManager().doRegulException(loonElement.getOpdracht(), Regulkode.RSZREGIME_NIET_GEPROGRAMMEERD);
    }

    @Override
    protected void verdeelBasisPensioenVastbenoemdenApk(AardKodeExtensie loonCode, Money bedrag) {
        Integer pensioenstelselCode = categorieKengetalStatuutPensioenstelsel.getPensioenStelsel().getCode();
        if (pensioenstelselCode > MIN_GRENS_PENSIOENSTELSEL_CODE_APK && pensioenstelselCode < MAX_GRENS_PENSIOENSTELSEL_CODE_APK) {
            DmfapplWnkengetal werknemersKengetal = categorieKengetalStatuutPensioenstelsel.getDmfapplWnkengetal();
            WerkgeversCategorie werkgeversCategorie = categorieKengetalStatuutPensioenstelsel.getWerkgeversCategorie();
            if (werknemersKengetal == DmfapplWnkengetal.STAGIAIR_VASTBENOEM_VAK_PRIVE_DMFA) {
                werknemersKengetal = DmfapplWnkengetal.VASTBENOEMDE;
            }

            WerknemersKengetalLooncode werknemersKengetalLooncode = getWerknemersKengetalLooncode(loonCode, werknemersKengetal);
            Integer loonCodeCode = werknemersKengetalLooncode.getLooncodeCode();
            boolean isOnderworpen = isOnderworpen(werkgeversCategorie, werknemersKengetal, loonCodeCode);
            boolean isPool2ter = isPool2Ter.check(categorieKengetalStatuutPensioenstelsel, getGegevensDatum());
            if (isOnderworpen && !isPool2ter) {
                loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_VASTBENOEMDEN_APK_KEY, bedrag);
                loonElement.removeProperty(RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY);
            }
        }
    }

    private boolean isOnderworpen(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Integer loonCodeCode) {
        List<DmfapplBasisBijdrage> basisBijdragen = getDmfapplBasisBijdrageService()
                .findByWerkgeversCategorieWerknemersKengetalLooncode(werkgeversCategorie, werknemersKengetal, loonCodeCode, getGegevensDatum());
        return basisBijdragen.stream()
                .map(DmfapplBasisBijdrage::getWerknemersKengetalBijdrage)
                .anyMatch(x -> x == DmfapplWnkengetal.BASISPENSBIJDR_STATUTAIRE_WERKNEMERS);
    }

    @Override
    protected Kengetal getWerknemersKengetal(DmfapplWnkengetal kengetal) {
        return new KengetalDmfa(kengetal);
    }

    @Override
    protected CategorieKengetal getCategorieKengetal(WerkgeversCategorie categorie, DmfapplWnkengetal kengetal) {
        return new CategorieKengetalDmfa(categorie, kengetal);
    }

    @Override
    protected CategorieMapper getCategorieMapper() {
        return new CategorieMapperDmfa();
    }

    @Override
    public WerknemersKengetalLooncode getWerknemersKengetalLooncode(AardKodeExtensie loonCode, DmfapplWnkengetal werknemersKengetal) {
        return new WerknemersKengetalLooncodeDmfa(loonCode, werknemersKengetal);
    }

    @Override
    protected void verdeelBasisPensioenMandatarissenNietBeschermd(AardKodeExtensie loonCode, Money bedrag) {
        if (LoonCodeTools.isGewoonLoon(loonCode) && isMandataris()) {
            getLoonElement().putProperty(RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, bedrag);
        }
    }

    private boolean isMandataris() {
        return getHoedanigheid() == Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD || getHoedanigheid() == Hoedanigheid.MANDATARISSEN;
    }

    @Override
    protected boolean heeftBasisRsz() {
        AardKodeExtensie loonCode = getLoonElement().getAardKodeExtensie();
        DmfapplWnkengetal dmfapplWnkengetal = categorieKengetalStatuutPensioenstelsel.getDmfapplWnkengetal();
        WerknemersKengetalLooncode werknemersKengetalLooncode = getWerknemersKengetalLooncode(loonCode, dmfapplWnkengetal);
        Integer looncodeCode = werknemersKengetalLooncode.getLooncodeCode();
        DmfaBezoldigingscode bezoldigingsCode = DmfaBezoldigingscode.getByCode(looncodeCode);
        return RszTools.heeftBasisRsz(loonCode) && !BEZOLDIGINGS_CODES_DMFA_ZONDER_BASIS.contains(bezoldigingsCode);
    }

    @Override
    public void verdeelBasisRszBasisBijdragenSpecialeGevallen(AardKodeExtensie loonCode, Money bedrag) {
        // Altijd voor bepaalde looncodes dingen berekenen
        LoonCodeDmfa loonCodeDmfa = new LoonCodeDmfa(loonCode.getCode());

        if (isMandataris()) {
            verdeelBasisRszBasisBijdragenSpecialeGevallenDubbelVakantiegeldMandataris(loonCodeDmfa, bedrag);
        } else {
            verdeelBasisRszBasisBijdragenSpecialeGevallenDubbelVakantiegeld(loonCodeDmfa, bedrag);
        }
    }

    void verdeelBasisRszBasisBijdragenSpecialeGevallenDubbelVakantiegeld(LoonCodeDmfa loonCodeDmfa, Money bedrag) {
        if (loonCodeDmfa.isSpecialeDubbelVakantiegeld()) {
            getLoonElement().putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
        }
    }

    void verdeelBasisRszBasisBijdragenSpecialeGevallenDubbelVakantiegeldMandataris(LoonCodeDmfa loonCodeDmfa, Money bedrag) {
        if (loonCodeDmfa.isSpecialeDubbelVakantiegeldMandataris()) {
            getLoonElement().putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY, bedrag);
        }
    }

    @Override
    protected List<DmfapplWnkengetal> getDmfapplBasisBijdragesHardCoded(WerknemersKengetalLooncode werknemersKengetalLooncode) {
        List<DmfapplWnkengetal> extraBasisBijdragen = new ArrayList<>();

        Integer looncodeCode = werknemersKengetalLooncode.getLooncodeCode();
        if (BEZOLDINGSCODES_MET_VOLLEDIGE_VRIJSTELING.contains(looncodeCode)) {
            extraBasisBijdragen.add(DmfapplWnkengetal.VOLLEDIGE_VRIJSTELLING);
        }
        return extraBasisBijdragen;
    }

    @Override
    protected KengetalMapper getWerknemersKengetalMapper() {
        return new KengetalMapperDmfa();
    }

}
